package com.restaurantcraft.entity.ai; import com.restaurantcraft.entity.*; import net.minecraft.world.entity.ai.goal.Goal; public class CustomerWaitOrderGoal extends Goal { private final CustomerEntity c; public CustomerWaitOrderGoal(CustomerEntity c){this.c=c;} public boolean canUse(){return c.state()==CustomerState.WAITING_FOR_ORDER||c.state()==CustomerState.ORDER_COMPLETED;} public void tick(){c.getNavigation().stop();} }
